const items = $input.all();
const results = items.map(item => item.json);

const health = {
  timestamp: new Date().toISOString(),
  postgres: {
    status: results[0]?.status || 'unknown',
    connections_active: results[0]?.connections_active || 0,
    connections_max: results[0]?.connections_max || 100,
    disk_usage_pct: results[0]?.disk_usage_pct || 0,
    replication_lag_ms: results[0]?.replication_lag_ms || 0,
    slow_queries: results[0]?.slow_queries || 0
  },
  redis: {
    status: results[1]?.status || 'unknown',
    memory_used_mb: results[1]?.memory_used_mb || 0,
    memory_max_mb: results[1]?.memory_max_mb || 0,
    connected_clients: results[1]?.connected_clients || 0,
    keys_total: results[1]?.keys_total || 0,
    ops_per_sec: results[1]?.ops_per_sec || 0
  },
  qdrant: {
    status: results[2]?.status === 'ok' ? 'healthy' : (results[2]?.status || 'unknown'),
    collections_count: results[2]?.collections_count || 0,
    points_total: results[2]?.points_total || 0,
    disk_usage_mb: results[2]?.disk_usage_mb || 0
  }
};

// Determine overall status
const statuses = [health.postgres.status, health.redis.status, health.qdrant.status];
const unhealthy = statuses.filter(s => s !== 'healthy' && s !== 'ok');
health.overall = unhealthy.length === 0 ? 'healthy' : 'degraded';

// Check thresholds
health.alerts = [];
if (health.postgres.connections_active > health.postgres.connections_max * 0.8) {
  health.alerts.push('PostgreSQL connection pool > 80%');
}
if (health.postgres.disk_usage_pct > 85) {
  health.alerts.push(`PostgreSQL disk usage at ${health.postgres.disk_usage_pct}%`);
}
if (health.redis.memory_used_mb > health.redis.memory_max_mb * 0.9) {
  health.alerts.push('Redis memory > 90% of max');
}
if (health.postgres.slow_queries > 5) {
  health.alerts.push(`${health.postgres.slow_queries} slow PostgreSQL queries detected`);
}

return [{ json: health }];
